import React, { useState, useEffect, useRef } from 'react';
import { searchMovies, suggestMovies } from '../services/api';
import './SearchBar.css';

const SearchBar = ({ onSearchResult }) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const searchRef = useRef(null);

  useEffect(() => {
    // Автодополнение при вводе
    const fetchSuggestions = async () => {
      if (query.length >= 2) {
        const results = await suggestMovies(query);
        setSuggestions(results);
        setShowSuggestions(true);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    };

    const delayDebounce = setTimeout(fetchSuggestions, 300);
    return () => clearTimeout(delayDebounce);
  }, [query]);

  useEffect(() => {
    // Закрыть подсказки при клике вне компонента
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsLoading(true);
    const results = await searchMovies(query);
    setIsLoading(false);

    if (onSearchResult) {
      onSearchResult(results, query); // Передаем и результаты, и запрос
    }
    setShowSuggestions(false);
  };

  const handleSuggestionClick = (suggestion) => {
    setQuery(suggestion.title);
    setShowSuggestions(false);
    // Автоматически выполняем поиск по выбранному suggestion
    handleSearch({ preventDefault: () => {} });
  };

  const handleClear = () => {
    setQuery('');
    if (onSearchResult) {
      onSearchResult(null, ''); // Сброс поиска
    }
  };

  return (
    <div className="search-container" ref={searchRef}>
      <form onSubmit={handleSearch} className="search-form">
        <input
          type="text"
          className="search-input"
          placeholder="Поиск фильмов..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onFocus={() => query.length >= 2 && setShowSuggestions(true)}
        />
        {query && (
          <button type="button" className="search-clear" onClick={handleClear}>
            ✕
          </button>
        )}
        <button type="submit" className="search-button" disabled={isLoading}>
          {isLoading ? '🔍' : '🔍'}
        </button>
      </form>

      {showSuggestions && suggestions.length > 0 && (
        <div className="suggestions-dropdown">
          {suggestions.map((suggestion) => (
            <div
              key={suggestion.id}
              className="suggestion-item"
              onClick={() => handleSuggestionClick(suggestion)}
            >
              <span className="suggestion-icon">🎬</span>
              <span className="suggestion-title">{suggestion.title}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default SearchBar;
